mapper.select:
/* IFacilityInfoMapper.selectAptCardList */ SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY ac.apt_cmplex_nm ASC) rn , ac.apt_cmplex_no aptCmplexNo , ac.apt_cmplex_nm aptCmplexNm , ac.sido_nm sidoNm , ac.sigungu_nm sigunguNm , ac.dorojuso dorojuso , ac.unit_cnt unitCnt , ac.dong_cnt dongCnt , ac.bld_yr bldYr , ( SELECT MIN(af.google_id) FROM attach_file af WHERE af.file_group_no = NVL(ac.rprsnt_img_file_no, ac.img_file_no) AND af.mime_type LIKE 'image/%' AND LOWER(af.file_og_name) NOT LIKE '%map%' AND LOWER(af.file_og_name) NOT LIKE '%지도%' AND LOWER(af.file_og_name) NOT LIKE '%road%' AND LOWER(af.file_og_name) NOT LIKE '%location%' ) AS rprsnt_img_file_no FROM apt_complex ac WHERE 1 = 1
AND ac.sido_nm = #{sidoNm}
AND ac.sigungu_nm = #{sigunguNm}
AND ac.apt_cmplex_nm LIKE '%' || #{keyword} || '%'
AND NVL(ac.unit_cnt, 0) < 300
AND NVL(ac.unit_cnt, 0) >= 300 AND NVL(ac.unit_cnt, 0) < 500
AND NVL(ac.unit_cnt, 0) >= 500 AND NVL(ac.unit_cnt, 0) < 1000
AND NVL(ac.unit_cnt, 0) >= 1000
) WHERE rn BETWEEN #{startRow} AND #{endRow}

/* IFacilityInfoMapper.selectAptCardTotalCount */ SELECT COUNT(*) FROM apt_complex ac WHERE 1 = 1
AND ac.sido_nm = #{sidoNm}
AND ac.sigungu_nm = #{sigunguNm}
AND ac.apt_cmplex_nm LIKE '%' || #{keyword} || '%'
AND NVL(ac.unit_cnt, 0) < 300
AND NVL(ac.unit_cnt, 0) >= 300 AND NVL(ac.unit_cnt, 0) < 500
AND NVL(ac.unit_cnt, 0) >= 500 AND NVL(ac.unit_cnt, 0) < 1000
AND NVL(ac.unit_cnt, 0) >= 1000
